namespace AddressApi.Domain.Entities;

public class Address
{
    public Guid Id { get; private set; }
    public string Street { get; private set; }
    public string City { get; private set; }
    public string State { get; private set; }
    public string PostalCode { get; private set; }

    public Address(string street, string city, string state, string postalCode)
    {
        Id = Guid.NewGuid();
        Street = street;
        City = city;
        State = state;
        PostalCode = postalCode;
    }
}

using MediatR;

namespace AddressApi.Application.Commands;

public record CreateAddressCommand(string Street, string City, string State, string PostalCode) : IRequest<Guid>;

using AddressApi.Domain.Entities;
using MediatR;

namespace AddressApi.Application.Handlers;

public class CreateAddressCommandHandler : IRequestHandler<CreateAddressCommand, Guid>
{
    public Task<Guid> Handle(CreateAddressCommand request, CancellationToken cancellationToken)
    {
        var address = new Address(request.Street, request.City, request.State, request.PostalCode);
        // Save to database (not implemented here)
        return Task.FromResult(address.Id);
    }
}

using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddEndpointsApiExplorer();
builder.Services.AddSwaggerGen();

var app = builder.Build();

app.UseSwagger();
app.UseSwaggerUI();

app.MapControllers();

app.Run();

using AddressApi.Application.Commands;
using MediatR;
using Microsoft.AspNetCore.Mvc;

namespace AddressApi.API.Controllers;

[ApiController]
[Route("api/[controller]")]
public class AddressController : ControllerBase
{
    private readonly IMediator _mediator;

    public AddressController(IMediator mediator)
    {
        _mediator = mediator;
    }

    [HttpPost]
    public async Task<IActionResult> CreateAddress([FromBody] CreateAddressCommand command)
    {
        var id = await _mediator.Send(command);
        return CreatedAtAction(nameof(CreateAddress), new { id }, id);
    }
}

using AddressApi.Application.Commands;
using AddressApi.Application.Handlers;
using FluentAssertions;
using Xunit;

namespace AddressApi.Tests.Handlers;

public class CreateAddressCommandHandlerTests
{
    [Fact]
    public async Task Handle_ShouldReturnNewAddressId()
    {
        var handler = new CreateAddressCommandHandler();
        var command = new CreateAddressCommand("Street", "City", "State", "PostalCode");

        var result = await handler.Handle(command, default);

        result.Should().NotBeEmpty();
    }
}
